#include <stdio.h>
#include <stdint.h>

const uint64_t MOD = 1000000007;

uint64_t powmod(uint64_t a, uint64_t b) {
    uint64_t res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        uint64_t n;
        scanf("%llu", &n);
        uint64_t sum = powmod(2, n);
        printf("%llu\n", sum);
    }
    return 0;
}

