import java.util.Scanner;

public class Main {
    static final long MOD = 1000000007;

    static long powmod(long a, long b) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long n = sc.nextLong();
            long sum = powmod(2, n);
            System.out.println(sum);
        }
    }
}

